package com.example.eventproducer.controller;

import org.apache.kafka.clients.producer.ProducerRecord;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.web.bind.annotation.*;

import java.nio.charset.StandardCharsets;
import java.util.Map;

@RestController
@RequestMapping("/events")
public class EventController {

    private static final String TOPIC = "event-tracking";

    @Autowired
    private KafkaTemplate<String, String> kafkaTemplate;

    @PostMapping
    public ResponseEntity<Void> publishEvent(@RequestBody String payload,
                                             @RequestHeader Map<String, String> requestHeaders) {

        ProducerRecord<String, String> record = new ProducerRecord<>(TOPIC, payload);

        requestHeaders.forEach((key, value) -> {
            if (isApplicationHeader(key)) {
                record.headers().add(key, value.getBytes(StandardCharsets.UTF_8));
            }
        });

        kafkaTemplate.send(record);
        return new ResponseEntity<>(HttpStatus.ACCEPTED);
    }

    private boolean isApplicationHeader(String headerName) {
        String h = headerName.toLowerCase();
        return h.equals("tracking-id") ||
               h.equals("user-id") ||
               h.startsWith("x-meta-");
    }
}